import axios from 'axios';

const API_URL = 'http://localhost:5032/api/seasons';

export const GetSeasons = async () => {
    try {
        const response = await axios.get(`${API_URL}`);
        return response.data;
    } catch (error) {
        console.error("Error fetching data: ", error);
    }
};
